/* Stepper Component Styles */
.journey-tracker {
  --tracker-primary-start: rgb(0, 255, 214);
  --tracker-primary-end: rgb(8, 226, 96);
  --tracker-secondary-text: rgba(0, 137, 78, 0.7647058824);
  --tracker-primary-text: #00894d;
  --tracker-shadow-color-light: rgba(5, 71, 17, 0.2);
  --tracker-shadow-color-dark: rgba(5, 71, 17, 0.3);
  --tracker-glass-light: rgba(255, 255, 255, 0.349);
  --tracker-glass-dark: rgba(255, 255, 255, 0.815);
  --tracker-border-color: white;

  width: 100%;
  max-width: 900px;
  margin: 50px auto;
  perspective: 1500px; /* Deeper perspective for a wider component */
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  color: var(--tracker-primary-text);
  box-sizing: border-box; /* Good practice */
}

.journey-path {
  display: flex;
  justify-content: space-around;
  align-items: center;
  position: relative;
  transform-style: preserve-3d;
  gap: 30px; /* Space between steps */
  padding: 20px;
}

/* Line connecting steps */
.journey-path::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 0;
  right: 0;
  height: 4px;
  background: linear-gradient(90deg, var(--tracker-primary-start), var(--tracker-primary-end));
  z-index: 0;
  transform: translateY(-50%) translate3d(0, 0, 10px); /* Bring line forward a bit */
  border-radius: 2px;
}

.path-stop {
  position: relative;
  flex: 1; /* Distribute space evenly */
  max-width: 200px;
  min-width: 150px;
  aspect-ratio: 1.2 / 1; /* Rectangular shape for card effect */
  border-radius: 30px;
  background: linear-gradient(135deg, var(--tracker-primary-start) 0%, var(--tracker-primary-end) 100%);
  transition: all 0.6s ease-in-out;
  transform-style: preserve-3d;
  box-shadow: var(--tracker-shadow-color-light) 0px 15px 25px -5px, var(--tracker-shadow-color-dark) 0px 5px 15px -5px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  z-index: 1; /* Ensure steps are above the line */
}

/* Active step styling */
.path-stop.is-active {
  box-shadow: var(--tracker-shadow-color-dark) 0px 25px 35px -10px, var(--tracker-shadow-color-light) 0px 10px 20px -5px;
  transform: translate3d(0, -10px, 40px);
}
.path-stop.is-active .stop-marker {
  transform: translate3d(0px, 0px, 35px) scale(1.1); /* Bring active marker further */
  box-shadow: var(--tracker-shadow-color-light) 0px 10px 15px -5px;
  /* Flipped gradient for active marker to make it slightly different */
  background: linear-gradient(0deg, var(--tracker-glass-dark) 0%, var(--tracker-glass-light) 100%);
}
.path-stop.is-active .detail-title {
    font-weight: 900;
}

.stop-marker {
  transform-style: preserve-3d;
  position: relative;
  width: 70px; /* Size of the circle */
  height: 70px;
  border-radius: 50%;
  background: linear-gradient(0deg, var(--tracker-glass-light) 0%, var(--tracker-glass-dark) 100%);
  backdrop-filter: blur(5px);
  -webkit-backdrop-filter: blur(5px);
  transform: translate3d(0px, 0px, 25px); /* Bring marker forward */
  border-left: 1px solid var(--tracker-border-color);
  border-bottom: 1px solid var(--tracker-border-color);
  transition: all 0.5s ease-in-out;
  display: grid;
  place-content: center;
  color: var(--tracker-primary-text);
  box-shadow: rgba(100, 100, 111, 0.1) 0px 5px 10px 0px;
}

.marker-text {
  font-size: 28px;
  font-weight: bold;
  transform: translate3d(0, 0, 5px); /* Add slight depth to text */
  text-shadow: 1px 1px 2px rgba(0,0,0,0.1);
  display: block; /* Default to show text */
}

.marker-icon {
  width: 30px;
  height: 30px;
  fill: var(--tracker-primary-text);
  transform: translate3d(0, 0, 5px); /* Same Z-depth as marker-text */
  transition: fill 0.3s ease-in-out;
  display: none; /* Default to hide icon */
}

/* Hide text for active, show icon */
.path-stop.is-active .marker-text {
    display: none;
}
.path-stop.is-active .marker-icon {
    display: block;
}

.stop-details {
  position: relative;
  padding: 15px 10px 0;
  text-align: center;
  transform: translate3d(0, 0, 26px); /* Bring details forward */
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.detail-title {
  display: block;
  color: var(--tracker-primary-text);
  font-weight: 700;
  font-size: 18px;
  margin-top: 5px;
}

.detail-description {
  display: block;
  color: var(--tracker-secondary-text);
  font-size: 13px;
}

/* Hover effects */
.path-stop:hover {
  transform: rotate3d(1, 1, 0, 10deg) translate3d(0, -15px, 60px); /* Lift and tilt on hover */
  box-shadow: var(--tracker-shadow-color-dark) 20px 30px 25px -20px, var(--tracker-shadow-color-light) 0px 15px 30px 0px;
}

.path-stop:hover .stop-marker {
  transform: translate3d(0px, 0px, 45px) scale(1.15); /* Marker pops out more */
  box-shadow: rgba(100, 100, 111, 0.3) 0px 15px 20px 0px;
}

/* Ensure active step still behaves well on hover */
.path-stop.is-active:hover {
    transform: rotate3d(1, 1, 0, 10deg) translate3d(0, -20px, 70px); /* Slightly more aggressive for active */
    box-shadow: var(--tracker-shadow-color-dark) 25px 40px 30px -20px, var(--tracker-shadow-color-light) 0px 20px 35px 0px;
}

.path-stop.is-active:hover .stop-marker {
    transform: translate3d(0px, 0px, 50px) scale(1.2);
    box-shadow: rgba(100, 100, 111, 0.4) 0px 20px 25px 0px;
}

/* Responsive adjustment for smaller screens */
@media (max-width: 768px) {
  .journey-path {
    flex-direction: column;
    align-items: center;
    gap: 60px; /* More space for vertical */
  }

  .journey-path::before {
    width: 4px;
    height: calc(100% - 120px); /* Adjust height for vertical line */
    top: 60px; /* Start below the first step */
    bottom: 60px; /* End above the last step */
    left: 50%;
    transform: translateX(-50%) translate3d(0, 0, 10px);
    background: linear-gradient(0deg, var(--tracker-primary-start), var(--tracker-primary-end));
  }

  .path-stop {
    width: 180px;
    margin: 0; /* Remove horizontal margin */
    aspect-ratio: unset; /* Allow height to adjust */
    padding: 20px;
    justify-content: flex-start; /* Align content from top */
  }

  .path-stop.is-active {
    transform: translate3d(0, 0, 40px); /* No Y translation needed for vertical active */
  }

  .path-stop:hover {
    transform: rotate3d(0, 1, 0, 15deg) translate3d(15px, 0, 60px); /* Tilt sideways for vertical */
  }

  .path-stop.is-active:hover {
    transform: rotate3d(0, 1, 0, 15deg) translate3d(20px, 0, 70px);
  }
}
